// Decide la sorgente della frase.
// Tre casi:
//  1. Input ricevuto da callback (regen) -> riusa la frase passata, flag is_reused
//  2. 30% -> rotta verso "Genera frase con OpenAI"
//  3. 70% -> pesca curata dal DB (priorita' fairness)
const Database = require('better-sqlite3');

const DB_PATH = process.env.QUOTES_DB_PATH || '/data/database/quotes.db';
const PROBABILITY_GENERATED = 0.30;

const incoming = $input.first() ? $input.first().json : {};

// Caso 1: invocato da callback con quote gia' decisa
if (incoming && incoming.quote_text && incoming.theme && incoming.mood) {
  return [{
    json: {
      source_type: incoming.source_type || 'curated',
      is_reused:   true,
      quote_id:    incoming.quote_id,
      quote_text:  incoming.quote_text,
      author:      incoming.author,
      source:      incoming.source,
      theme:       incoming.theme,
      mood:        incoming.mood
    }
  }];
}

// Caso 2/3: 70/30
const useGenerated = Math.random() < PROBABILITY_GENERATED;

if (useGenerated) {
  return [{
    json: { source_type: 'generated' }
  }];
}

const db = new Database(DB_PATH, { readonly: true });
try {
  const row = db.prepare(`
    SELECT id, text, author, source, theme, mood
    FROM quotes
    WHERE last_used_at IS NULL
       OR julianday('now') - julianday(last_used_at) > 90
    ORDER BY used_count ASC, COALESCE(last_used_at, '1970-01-01') ASC, RANDOM()
    LIMIT 1
  `).get();

  if (!row) {
    return [{ json: { source_type: 'generated' } }];
  }

  return [{
    json: {
      source_type: 'curated',
      quote_id:   row.id,
      quote_text: row.text,
      author:     row.author,
      source:     row.source,
      theme:      row.theme,
      mood:       row.mood
    }
  }];
} finally {
  db.close();
}

// Aggiorna used_count e last_used_at della citazione curata appena pescata.
// Skip se la frase e' stata riusata (regen via callback): l'aggiornamento e' gia' avvenuto al primo pick.
const Database = require('better-sqlite3');
const DB_PATH = process.env.QUOTES_DB_PATH || '/data/database/quotes.db';

const item = $input.first().json;

if (!item.is_reused && item.quote_id) {
  const db = new Database(DB_PATH);
  try {
    db.prepare(`
      UPDATE quotes
      SET used_count   = used_count + 1,
          last_used_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `).run(item.quote_id);
  } finally {
    db.close();
  }
}

// Pass-through: Merge a valle si aspetta gli stessi campi.
return [{ json: item }];

