// Parsa la risposta di OpenAI Chat Completions e salva in `generated_quotes`.
const Database = require('better-sqlite3');
const DB_PATH = process.env.QUOTES_DB_PATH || '/data/database/quotes.db';

const response = $input.first().json;
const rawText = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '';

// Con response_format=json_object dovrebbe essere gia' JSON pulito,
// ma teniamo una rete di sicurezza per estrarre la prima coppia di {} se serve.
const cleaned = rawText
  .replace(/^[\s\S]*?({[\s\S]*})[\s\S]*$/, '$1')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Risposta OpenAI non e\' JSON valido. Raw: ' + rawText.slice(0, 300));
}

if (!parsed.text || !parsed.theme || !parsed.mood) {
  throw new Error('JSON mancante campi obbligatori (text/theme/mood). Raw: ' + cleaned);
}

const sourceTag = `gpt-5-mini / structure=${parsed.structure_used || 'unknown'}`;

const db = new Database(DB_PATH);
let generatedId;
try {
  const result = db.prepare(`
    INSERT INTO generated_quotes (text, author, source, theme, mood)
    VALUES (?, 'Alien Mind', ?, ?, ?)
  `).run(parsed.text, sourceTag, parsed.theme, parsed.mood);
  generatedId = result.lastInsertRowid;
} finally {
  db.close();
}

return [{
  json: {
    source_type: 'generated',
    quote_id:    generatedId,
    quote_text:  parsed.text,
    author:      'Alien Mind',
    source:      sourceTag,
    theme:       parsed.theme,
    mood:        parsed.mood
  }
}];

