// Parsa il JSON visivo prodotto da OpenAI e lo passa al nodo successivo (immagini).
const response = $input.first().json;
const rawText = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '';
const cleaned = rawText.replace(/^[\s\S]*?({[\s\S]*})[\s\S]*$/, '$1').trim();

let visual;
try {
  visual = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Visual JSON non parsabile. Raw: ' + rawText.slice(0, 300));
}

if (!visual.visual_prompt_en) {
  throw new Error('Manca visual_prompt_en nel JSON visual.');
}

// Combina con i campi del quote (vengono dal Merge upstream).
const quote = $('Merge').first().json;

return [{
  json: {
    ...quote,
    visual_prompt_en:   visual.visual_prompt_en,
    composition_notes:  visual.composition_notes || '',
    color_palette:      visual.color_palette || [],
    text_position:      visual.text_position || 'bottom',
    negative_elements:  visual.negative_elements || []
  }
}];

// Composizione tipografia: testo bianco su immagine, posizione top/bottom/split.
// Versione lavorativa: SVG overlay con font system, raffinata in Step 6 con font custom.
const sharp = require('sharp');

const item = $input.first();
const quote = item.json;

// L'immagine arriva da OpenAI come b64_json
const openaiResp = $('OpenAI gpt-image-1.5').first().json;
const b64 = openaiResp.data && openaiResp.data[0] && openaiResp.data[0].b64_json;
if (!b64) throw new Error('OpenAI ha risposto senza b64_json. Resp keys: ' + Object.keys(openaiResp).join(','));
const imgBuffer = Buffer.from(b64, 'base64');

// Capitalize prima lettera di ogni parola (Unicode-aware)
function capitalize(s) {
  return s.replace(/(^|\s)(\p{L})/gu, (_, sep, ch) => sep + ch.toUpperCase());
}

function wrap(text, max = 32) {
  const words = text.split(/\s+/);
  const lines = [];
  let line = '';
  for (const w of words) {
    if ((line + ' ' + w).trim().length > max && line) {
      lines.push(line.trim());
      line = w;
    } else {
      line = line ? line + ' ' + w : w;
    }
  }
  if (line) lines.push(line.trim());
  return lines;
}

function escapeXML(s) {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

const W = 1080, H = 1350;
const phrase = capitalize(quote.quote_text);
const lines = wrap(phrase, 32);
const fontSize = 56;
const lineHeight = Math.round(fontSize * 1.3);
const pad = 100;
const pos = quote.text_position || 'bottom';

let textElems = '';
function renderLine(line, y) {
  return `<text x="${W/2}" y="${y}" font-family="'DejaVu Sans', Arial, sans-serif" font-size="${fontSize}" font-weight="700" fill="white" text-anchor="middle" filter="url(#shadow)">${escapeXML(line)}</text>`;
}

if (pos === 'split') {
  const half = Math.ceil(lines.length / 2);
  const top = lines.slice(0, half);
  const bot = lines.slice(half);
  top.forEach((l, i) => textElems += renderLine(l, pad + lineHeight + i * lineHeight));
  bot.forEach((l, i) => textElems += renderLine(l, H - pad - (bot.length - 1 - i) * lineHeight));
} else if (pos === 'top') {
  lines.forEach((l, i) => textElems += renderLine(l, pad + lineHeight + i * lineHeight));
} else {
  // bottom (default)
  const total = lines.length * lineHeight;
  const startY = H - pad - total + lineHeight;
  lines.forEach((l, i) => textElems += renderLine(l, startY + i * lineHeight));
}

const svg = `<svg width="${W}" height="${H}" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
      <feGaussianBlur in="SourceAlpha" stdDeviation="6"/>
      <feOffset dx="0" dy="2"/>
      <feComponentTransfer><feFuncA type="linear" slope="1.5"/></feComponentTransfer>
      <feMerge><feMergeNode/><feMergeNode in="SourceGraphic"/></feMerge>
    </filter>
  </defs>
  ${textElems}
</svg>`;

const composed = await sharp(imgBuffer)
  .resize(W, H, { fit: 'cover' })
  .composite([{ input: Buffer.from(svg), top: 0, left: 0 }])
  .png()
  .toBuffer();

// Filename: YYYYMMDD-HHmm-{first8charsOfQuote}.png
const pad2 = (n) => String(n).padStart(2, '0');
const d = new Date();
const stamp = `${d.getFullYear()}${pad2(d.getMonth()+1)}${pad2(d.getDate())}-${pad2(d.getHours())}${pad2(d.getMinutes())}`;
const slug = (quote.quote_text || '').replace(/[^a-zA-Z0-9]/g, '').slice(0, 8) || 'untitled';
const fileName = `${stamp}-${slug}.png`;

return [{
  json: {
    ...quote,
    image_filename: fileName,
    image_size: composed.length
  },
  binary: {
    data: {
      data:     composed.toString('base64'),
      mimeType: 'image/png',
      fileName: fileName,
      fileExtension: 'png'
    }
  }
}];

// INSERT del post in tabella `posts` con status='draft'.
// Salva post_id e drive URL per il messaggio Telegram successivo.
const Database = require('better-sqlite3');
const DB_PATH = process.env.QUOTES_DB_PATH || '/data/database/quotes.db';

const quote = $('Compose typography').first().json;
const drive = $input.first().json; // output del nodo Drive Upload

const driveId  = drive.id || '';
const driveUrl = drive.webViewLink || drive.webContentLink || `https://drive.google.com/file/d/${driveId}/view`;

const db = new Database(DB_PATH);
let postId;
try {
  const result = db.prepare(`
    INSERT INTO posts (quote_id, quote_source, image_url_drive, status)
    VALUES (?, ?, ?, 'draft')
  `).run(quote.quote_id, quote.source_type, driveUrl);
  postId = result.lastInsertRowid;
} finally {
  db.close();
}

return [{
  json: {
    ...quote,
    post_id:          postId,
    drive_file_id:    driveId,
    image_url_drive:  driveUrl
  },
  binary: $input.first().binary  // mantieni il binario per il Telegram a valle
}];
